            dist_o = dist_manh(nx, ny, ox, oy)
            score = (-best_r) * 1000 - dist_o
            if best_score is None or score > best_score:
                best_score = score
                best_move = (dx, dy)
    else:
        for dx, dy in dirs:
            nx, ny = sx + dx, sy + dy
            if not inb(nx, ny):
                continue
            score = dist_manh(nx, ny, ox, oy)
            if best_score is None or score > best_score:
                best_score = score
                best_move = (dx, dy)

    return [int(best_move[0]), int(best_move[1])]
